/**
 * @summary Follow or unfollow a wallet
 */
export const getToggleFollowUrl = () => {
  return `/api/follows`;
};

export const toggleFollow = async (
  toggleFollowBody: ToggleFollowBody,
  options?: RequestInit,
): Promise<ToggleFollow200> => {
  return customFetch<ToggleFollow200>(getToggleFollowUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(toggleFollowBody),
  });
};

export const getToggleFollowMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof toggleFollow>>,
    TError,
    { data: BodyType<ToggleFollowBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof toggleFollow>>,
  TError,
  { data: BodyType<ToggleFollowBody> },
  TContext
> => {
  const mutationKey = ["toggleFollow"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof toggleFollow>>,
    { data: BodyType<ToggleFollowBody> }
  > = (props) => {
    const { data } = props ?? {};

    return toggleFollow(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ToggleFollowMutationResult = NonNullable<
  Awaited<ReturnType<typeof toggleFollow>>
>;
export type ToggleFollowMutationBody = BodyType<ToggleFollowBody>;
