/**
 * @summary Check if follower_wallet follows followed_wallet
 */
export const getCheckFollowUrl = (params: CheckFollowParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/follows/check?${stringifiedParams}`
    : `/api/follows/check`;
};

export const checkFollow = async (
  params: CheckFollowParams,
  options?: RequestInit,
): Promise<CheckFollow200> => {
  return customFetch<CheckFollow200>(getCheckFollowUrl(params), {
    ...options,
    method: "GET",
  });
};

